1	import {SqlTableSuffix} from "@webui/common/config";
2	import {Nullable} from "@webui/common/utility-types";
3	
4	import {querySql} from "../../../api/sql";
5	import {settings} from "../../../settings";
6	import {
7	    CLP_ARCHIVES_TABLE_COLUMN_NAMES,
8	    CLP_FILES_TABLE_COLUMN_NAMES,
9	} from "../sqlConfig";
10	
11	
12	/**
13	 * Result from SQL details query.
14	 */
15	interface DetailsItem {
16	    begin_timestamp: Nullable<number>;
17	    end_timestamp: Nullable<number>;
18	    num_files: Nullable<number>;
19	    num_messages: Nullable<number>;
20	}
21	
22	/**
23	 * Default values for details when no data is available.
24	 */
25	const DETAILS_DEFAULT: DetailsItem = {
26	    begin_timestamp: null,
27	    end_timestamp: null,
28	    num_files: 0,
29	    num_messages: 0,
30	};
31	
32	/**
33	 * Builds the query string for details stats when using CLP storage engine (i.e. no datasets).
34	 *
35	 * @return
36	 */
37	const getDetailsSql = () => `
38	SELECT
39	    a.begin_timestamp         AS begin_timestamp,
40	    a.end_timestamp           AS end_timestamp,
41	    b.num_files               AS num_files,
42	    b.num_messages            AS num_messages
43	FROM
44	(
45	    SELECT
46	        MIN(${CLP_ARCHIVES_TABLE_COLUMN_NAMES.BEGIN_TIMESTAMP})   AS begin_timestamp,
47	        MAX(${CLP_ARCHIVES_TABLE_COLUMN_NAMES.END_TIMESTAMP})     AS end_timestamp
48	    FROM ${settings.SqlDbClpArchivesTableName}
49	) a,
50	(
51	    SELECT
52	        COUNT(DISTINCT ${CLP_FILES_TABLE_COLUMN_NAMES.ORIG_FILE_ID})   AS num_files,
53	        CAST(
54	            COALESCE(
55	                SUM(${CLP_FILES_TABLE_COLUMN_NAMES.NUM_MESSAGES}),
56	                0
57	            ) AS UNSIGNED
58	        ) AS num_messages
59	    FROM ${settings.SqlDbClpFilesTableName}
60	) b;
61	`;
62	
63	/**
64	 * Builds the query string for details stats when using CLP-S storage engine
65	 * (i.e. multiple datasets).
66	 *
67	 * @param datasetNames
68	 * @return
69	 */
70	const buildMultiDatasetDetailsSql = (datasetNames: string[]): string => {
71	    const archiveQueries = datasetNames.map((name) => `
72	    SELECT
73	      MIN(${CLP_ARCHIVES_TABLE_COLUMN_NAMES.BEGIN_TIMESTAMP}) AS begin_timestamp,
74	      MAX(${CLP_ARCHIVES_TABLE_COLUMN_NAMES.END_TIMESTAMP}) AS end_timestamp
75	    FROM ${settings.SqlDbClpTablePrefix}${name}_${SqlTableSuffix.ARCHIVES}
76	  `);
77	
78	    const fileQueries = datasetNames.map((name) => `
79	    SELECT
80	      COUNT(DISTINCT ${CLP_FILES_TABLE_COLUMN_NAMES.ORIG_FILE_ID}) AS num_files,
81	      CAST(
82	        COALESCE(SUM(${CLP_FILES_TABLE_COLUMN_NAMES.NUM_MESSAGES}), 0) AS UNSIGNED
83	      ) AS num_messages
84	    FROM ${settings.SqlDbClpTablePrefix}${name}_${SqlTableSuffix.FILES}
85	  `);
86	
87	    return `
88	    SELECT
89	      a.begin_timestamp,
90	      a.end_timestamp,
91	      b.num_files,
92	      b.num_messages
93	    FROM
94	    (
95	      SELECT
96	        MIN(begin_timestamp) AS begin_timestamp,
97	        MAX(end_timestamp)   AS end_timestamp
98	      FROM (
99	        ${archiveQueries.join("\nUNION ALL\n")}
100	      ) AS archives_combined
101	    ) a,
102	    (
103	      SELECT
104	        SUM(num_files)    AS num_files,
105	        SUM(num_messages) AS num_messages
106	      FROM (
107	        ${fileQueries.join("\nUNION ALL\n")}
108	      ) AS files_combined
109	    ) b;
110	  `;
111	};
112	
113	/**
114	 * Executes details SQL query and extracts details result.
115	 *
116	 * @param sql
117	 * @return
118	 * @throws {Error} if query result does not contain data
119	 */
120	const executeDetailsQuery = async (sql: string): Promise<DetailsItem> => {
121	    const resp = await querySql<DetailsItem[]>(sql);
122	    const [detailsResult] = resp.data;
123	    if ("undefined" === typeof detailsResult) {
124	        throw new Error("Details result does not contain data.");
125	    }
126	
127	    return detailsResult;
128	};
129	
130	/**
131	 * Fetches details statistics when using CLP storage engine.
132	 *
133	 * @return
134	 */
135	const fetchClpDetails = async (): Promise<DetailsItem> => {
136	    const sql = getDetailsSql();
137	    return executeDetailsQuery(sql);
138	};
139	
140	/**
141	 * Fetches details statistics when using CLP-S storage engine.
142	 *
143	 * @param datasetNames
144	 * @return
145	 */
146	const fetchClpsDetails = async (
147	    datasetNames: string[]
148	): Promise<DetailsItem> => {
149	    if (0 === datasetNames.length) {
150	        return DETAILS_DEFAULT;
151	    }
152	    const sql = buildMultiDatasetDetailsSql(datasetNames);
153	    return executeDetailsQuery(sql);
154	};
155	
156	export type {DetailsItem};
157	export {
158	    DETAILS_DEFAULT,
159	    fetchClpDetails,
160	    fetchClpsDetails,
161	};
