19	/**
20	 * Renders space savings card.
21	 *
22	 * @return
23	 */
24	const SpaceSavings = () => {
25	    const {token} = theme.useToken();
26	
27	    const {data: datasetNames = [], isSuccess: isSuccessDatasetNames} = useQuery({
28	        queryKey: ["datasets"],
29	        queryFn: fetchDatasetNames,
30	        enabled: CLP_STORAGE_ENGINES.CLP_S === SETTINGS_STORAGE_ENGINE,
31	    });
32	
33	    const {data: spaceSavings = SPACE_SAVINGS_DEFAULT, isPending} = useQuery({
34	        queryKey: [
35	            "space-savings",
36	            datasetNames,
37	        ],
38	        queryFn: async () => {
39	            if (CLP_STORAGE_ENGINES.CLP === SETTINGS_STORAGE_ENGINE) {
40	                return fetchClpSpaceSavings();
41	            }
42	
43	            return fetchClpsSpaceSavings(datasetNames);
44	        },
45	        enabled: CLP_STORAGE_ENGINES.CLP === SETTINGS_STORAGE_ENGINE || isSuccessDatasetNames,
46	    });
47	
48	    const compressedSize = spaceSavings.total_compressed_size;
49	    const uncompressedSize = spaceSavings.total_uncompressed_size;
50	
51	    const spaceSavingsPercent = (0 !== uncompressedSize) ?
52	        100 * (1 - (compressedSize / uncompressedSize)) :
53	        0;
54	
55	    const spaceSavingsPercentText = `${spaceSavingsPercent.toFixed(2)}%`;
56	
57	    return (
58	        <div className={styles["spaceSavingsGrid"]}>
59	            <div className={styles["spaceSavingsCard"]}>
60	                <DashboardCard
61	                    backgroundColor={token.colorPrimary}
62	                    isLoading={isPending}
63	                    title={"Space Savings"}
64	                    titleColor={token.colorWhite}
65	                >
66	                    <Stat
67	                        color={token.colorWhite}
68	                        fontSize={"5.5rem"}
69	                        text={spaceSavingsPercentText}/>
70	                </DashboardCard>
71	            </div>
72	            <UncompressedSize
73	                isLoading={isPending}
74	                uncompressedSize={uncompressedSize}/>
75	            <CompressedSize
76	                compressedSize={compressedSize}
77	                isLoading={isPending}/>
78	        </div>
79	    );
80	};
81	
82	export default SpaceSavings;
