5	import {CLP_ARCHIVES_TABLE_COLUMN_NAMES} from "../sqlConfig";
6	
7	
8	/**
9	 * Result from sql space savings query.
10	 */
11	interface SpaceSavingsItem {
12	    total_uncompressed_size: number;
13	    total_compressed_size: number;
14	}
15	
16	/**
17	 * Default values for space savings when no data is available.
18	 */
19	const SPACE_SAVINGS_DEFAULT: SpaceSavingsItem = {
20	    total_compressed_size: 0,
21	    total_uncompressed_size: 0,
22	};
23	
24	
25	/**
26	 * Builds the query string for space savings stats when using CLP storage engine (i.e. no datasets).
27	 *
28	 * @return
29	 */
30	const getSpaceSavingsSql = () => `
31	SELECT
32	    CAST(
33	        COALESCE(
34	            SUM(${CLP_ARCHIVES_TABLE_COLUMN_NAMES.UNCOMPRESSED_SIZE}),
35	            0
36	        ) AS UNSIGNED
37	    ) AS total_uncompressed_size,
38	    CAST(
39	        COALESCE(
40	            SUM(${CLP_ARCHIVES_TABLE_COLUMN_NAMES.SIZE}),
41	            0
42	        ) AS UNSIGNED
43	    ) AS total_compressed_size
44	FROM ${settings.SqlDbClpArchivesTableName}
45	`;
46	
47	/**
48	 * Builds the query string for space savings stats when using CLP-S storage
49	 * engine (i.e. multiple datasets).
50	 *
51	 * @param datasetNames
52	 * @return
53	 */
54	const buildMultiDatasetSpaceSavingsSql = (datasetNames: string[]): string => {
55	    const archiveQueries = datasetNames.map((name) => `
56	    SELECT
57	        ${CLP_ARCHIVES_TABLE_COLUMN_NAMES.UNCOMPRESSED_SIZE},
58	        ${CLP_ARCHIVES_TABLE_COLUMN_NAMES.SIZE}
59	    FROM ${settings.SqlDbClpTablePrefix}${name}_${SqlTableSuffix.ARCHIVES}
60	    `);
61	
62	    return `
63	    SELECT
64	        CAST(
65	            COALESCE(
66	                SUM(${CLP_ARCHIVES_TABLE_COLUMN_NAMES.UNCOMPRESSED_SIZE}),
67	                0
68	            ) AS UNSIGNED
69	        ) AS total_uncompressed_size,
70	        CAST(
71	            COALESCE(
72	                SUM(${CLP_ARCHIVES_TABLE_COLUMN_NAMES.SIZE}),
73	                0
74	            ) AS UNSIGNED
75	        ) AS total_compressed_size
76	    FROM (
77	        ${archiveQueries.join("\nUNION ALL\n")}
78	    ) AS archives_combined
79	    `;
80	};
81	
82	/**
83	 * Executes space savings SQL query and extracts space savings result.
84	 *
85	 * @param sql
86	 * @return
87	 * @throws {Error} if query result does not contain data
88	 */
89	const executeSpaceSavingsQuery = async (sql: string): Promise<SpaceSavingsItem> => {
90	    const resp = await querySql<SpaceSavingsItem[]>(sql);
91	    const [spaceSavingsResult] = resp.data;
92	    if ("undefined" === typeof spaceSavingsResult) {
93	        throw new Error("Space savings result does not contain data.");
94	    }
95	
96	    return spaceSavingsResult;
97	};
98	
99	/**
100	 * Fetches space savings statistics when using CLP storage engine.
101	 *
102	 * @return
103	 */
104	const fetchClpSpaceSavings = async (): Promise<SpaceSavingsItem> => {
105	    const sql = getSpaceSavingsSql();
106	    return executeSpaceSavingsQuery(sql);
107	};
108	
109	/**
110	 * Fetches space savings statistics when using CLP-S storage engine.
111	 *
112	 * @param datasetNames
113	 * @return
114	 */
115	const fetchClpsSpaceSavings = async (
116	    datasetNames: string[]
117	): Promise<SpaceSavingsItem> => {
118	    if (0 === datasetNames.length) {
119	        return SPACE_SAVINGS_DEFAULT;
120	    }
121	    const sql = buildMultiDatasetSpaceSavingsSql(datasetNames);
