1	import {useQuery} from "@tanstack/react-query";
2	import {hc} from "hono/client";
3	
4	import {Card, CardContent, CardHeader, CardTitle} from "@/components/ui/card";
5	import {Bar, BarChart, ResponsiveContainer, XAxis, YAxis, Tooltip} from "recharts";
6	
7	import type {AppType} from "@webui/server/hono-app";
8	
9	
10	type LogtypeStat = {
11	    logtype: string;
12	    count: number;
13	    template: string;
14	};
15	
16	type LogtypeStatsResponse = {
17	    archiveId: string;
18	    logtypes: LogtypeStat[];
19	    totalCount: number;
20	};
21	
22	const api = hc<AppType>("/");
23	
24	/**
25	 * Renders the Stats tab showing logtype occurrence charts and summary cards.
26	 */
27	const StatsTab = () => {
28	    const {data, isLoading, error} = useQuery({
29	        queryKey: ["logtype-stats"],
30	        queryFn: async () => {
31	            const res = await api.api.logtype_stats.$get({
32	                query: {archive_id: "latest"},
33	            });
34	            return res.json() as Promise<LogtypeStatsResponse>;
35	        },
36	    });
37	
38	    if (isLoading) {
39	        return <div className="p-4 text-sm text-muted-foreground">Loading stats...</div>;
40	    }
41	
42	    if (error) {
43	        return <div className="p-4 text-sm text-red-600">Error: {error.message}</div>;
