14	/**
15	 * Counts the number of %VAR% placeholders in a logtype template string.
16	 * Variables are encoded as %VAR% in log-surgeon/CLP-S logtype templates.
17	 */
18	function countVariables(template: string): number {
19	  const matches = template.match(/%VAR%/g);
20	  return matches ? matches.length : 0;
21	}
