23	/**
24	 * Analyzes logtypes to detect shared nodes — variables at the same index
25	 * position that appear in multiple logtypes. When a shared node has
26	 * inconsistent types, it indicates a deduplication trap in the schema tree
27	 * that can cause ambiguous query results.
28	 */
29	function analyzeSharedNodes(
30	  logtypes: Array<{logtype: string; template: string; variables: Array<{index: number; type: string}>}>,
31	): SharedNodeWarning[] {
32	  const indexMap = new Map<number, Array<{logtype: string; type: string}>>();
33	
34	  for (const entry of logtypes) {
35	    for (const v of entry.variables) {
36	      if (!indexMap.has(v.index)) {
37	        indexMap.set(v.index, []);
38	      }
39	      indexMap.get(v.index)!.push({logtype: entry.logtype, type: v.type});
40	    }
41	  }
42	
43	  const warnings: SharedNodeWarning[] = [];
44	  for (const [index, occurrences] of indexMap) {
45	    if (occurrences.length > 1) {
46	      const types = new Set(occurrences.map((o) => o.type));
47	      if (types.size > 1) {
48	        warnings.push({
49	          variableIndex: index,
50	          types,
51	          logtypes: occurrences.map((o) => o.logtype),
52	          message: `Variable at position ${index} appears in ${occurrences.length} logtypes with inconsistent types (${[...types].join(", ")}). This creates a shared node in the schema tree that may cause ambiguous query results.`,
53	        });
54	      }
55	    }
56	  }
57	
58	  return warnings;
59	}
