69	/** Simple in-memory rate limiter */
70	class RateLimiter {
71	    private hits = new Map<string, {count: number; resetAt: number}>();
72	
73	    private maxHits: number;
74	
75	    private windowMs: number;
76	
77	    constructor (maxHits: number, windowMs: number) {
78	        this.maxHits = maxHits;
79	        this.windowMs = windowMs;
80	    }
81	
82	    check (ip: string): {allowed: boolean; remaining: number; resetAt: number} {
83	        const now = Date.now();
84	        let entry = this.hits.get(ip);
85	        if (!entry || now >= entry.resetAt) {
86	            entry = {count: 0, resetAt: now + this.windowMs};
87	            this.hits.set(ip, entry);
88	        }
89	        entry.count++;
90	        const allowed = entry.count <= this.maxHits;
91	        return {allowed: allowed, remaining: Math.max(0, this.maxHits - entry.count), resetAt: entry.resetAt};
92	    }
93	}
