95	const dashboardLimiter = new RateLimiter(RATE_LIMIT_MAX_HITS, RATE_LIMIT_WINDOW_MS);
96	
97	/**
98	 * Hono app for dashboard + datasource routes.
99	 * Must use chained route definitions for AppType inference.
100	 */
101	export const honoApp = new Hono()
102	
103	// NFR-12: Reject X-CLP-* headers from untrusted sources (spoofing prevention)
104	// In production: without a gateway, any x-clp-* header is spoofed → reject.
105	// With a gateway, only x-clp-role is trusted; other x-clp-* headers are suspicious → reject.
106	// Gateway marker is preserved here for NFR-11 to check, then deleted in NFR-11 after RBAC.
107	    .use("/api/*", async (c, next) => {
108	        if (isProduction()) {
109	            const hasGatewayHeader = Boolean(c.req.header(GATEWAY_HEADER));
110	            for (const [key] of c.req.raw.headers.entries()) {
111	                if (key.startsWith(CLP_HEADER_PREFIX) && key !== GATEWAY_HEADER) {
112	                    if (!hasGatewayHeader) {
113	                        c.status(HTTP_FORBIDDEN);
114	
115	                        return c.json({error: `Rejected spoofed header: ${key}`});
116	                    } else if (key !== "x-clp-role") {
117	                        // Gateway present but non-role x-clp-* header is suspicious
118	                        c.status(HTTP_FORBIDDEN);
119	
120	                        return c.json({error: `Rejected spoofed header: ${key}`});
121	                    }
122	                }
123	            }
124	        }
125	
126	        return next();
127	    })
128	
129	// NFR-11: RBAC enforcement in production mode when a gateway is present.
130	// The gateway is responsible for setting x-clp-role based on authenticated user
131	// permissions. Without a gateway, requests are direct from trusted clients and
132	// all operations are permitted.
133	    .use("/api/*", async (c, next) => {
134	        if (!isProduction()) {
135	            return next();
136	        }
137	        const hasGateway = Boolean(c.req.header(GATEWAY_HEADER));
138	        if (!hasGateway) {
139	            return next();
140	        }
141	        const role = getRole(c);
142	        const {method} = c.req;
143	
144	        // Write operations require editor role; read operations allow viewer
145	        if (WRITE_METHODS.has(method) && !hasRole(role, "editor")) {
146	            c.status(HTTP_FORBIDDEN);
147	
148	            return c.json({error: "Insufficient permissions for this operation"});
149	        }
150	
151	        // Strip gateway marker so downstream can't re-use it
152	        c.req.raw.headers.delete(GATEWAY_HEADER);
153	
154	        return next();
155	    })
156	    .use("/api/dashboards/*", async (c, next) => {
157	        const ip = c.req.raw.headers.get("x-forwarded-for")?.split(",")[0]?.trim() ?? c.req.raw.headers.get("x-real-ip") ?? "unknown";
158	        const {allowed, remaining, resetAt} = dashboardLimiter.check(ip);
159	        c.header("X-RateLimit-Remaining", String(remaining));
160	        c.header("X-RateLimit-Reset", String(Math.ceil(resetAt / MS_PER_SECOND)));
161	        if (!allowed) {
162	            c.status(HTTP_RATE_LIMITED);
163	
164	            return c.json({error: "Rate limit exceeded. Try again later."});
165	        }
166	
167	        return next();
168	    })
169	    .use("/api/dashboards/*", async (c, next) => {
170	        const contentLength = c.req.raw.headers.get("content-length");
171	        if (contentLength && parseInt(contentLength, 10) > MAX_BODY_SIZE) {
172	            c.status(HTTP_PAYLOAD_TOO_LARGE);
173	
174	            return c.json({error: "Request body exceeds 1MB limit"});
175	        }
176	
177	        return next();
178	    })
179	
180	// NFR: Request timeout — prevents long-running queries from blocking the server
181	    .use("/api/*", async (c, next) => {
182	        const controller = new AbortController();
183	        const timeout = setTimeout(() => {
184	            controller.abort();
185	        }, SERVER_REQUEST_TIMEOUT_MS);
186	
187	        c.req.raw.signal.addEventListener("abort", () => {
188	            controller.abort();
189	        });
190	
191	        try {
192	            await Promise.race([
193	                next(),
194	                new Promise((resolve) => {
195	                    controller.signal.addEventListener("abort", () => {
196	                        resolve(null);
197	                    });
198	                }),
199	            ]);
200	        } finally {
201	            clearTimeout(timeout);
202	        }
203	
204	        if (controller.signal.aborted && !c.req.raw.signal.aborted) {
205	            c.status(HTTP_REQUEST_TIMEOUT);
206	
207	            return c.json({error: "Request timed out"});
208	        }
209	
210	        return c.body(null);
211	    })
212	// NFR: Response payload size limit — prevents sending arbitrarily large JSON responses
213	    .use("/api/*", async (c, next) => {
214	        await next();
215	        const contentType = c.res.headers.get("content-type") ?? "";
216	        if (contentType.includes("application/json")) {
217	            const body = c.res.clone().body;
218	            if (body) {
219	                const reader = body.getReader();
220	                let totalBytes = 0;
221	                // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
222	                while (true) {
223	                    const {done, value} = await reader.read();
224	                    if (done) break;
225	                    totalBytes += value.length;
226	                    if (totalBytes > MAX_RESPONSE_SIZE) {
227	                        reader.cancel().catch(() => {});
228	                        c.res = c.json({error: `Response payload exceeds ${MAX_RESPONSE_SIZE / BYTES_PER_MB}MB limit`}, 413);
229	                        return;
230	                    }
231	                }
232	            }
233	        }
234	    })
235	    .route("/api/dashboards", dashboardRoutes)
236	    .route("/api/datasource", datasourceRoutes)
237	    .route("/api/logtype-stats", logtypeStatsRoutes)
238	    .route("/api/schema-tree", schemaTreeRoutes)
239	    .route("/api/schemas", schemaRoutes);
240	
241	/** Export AppType for client-side typed RPC via hc<AppType>() */
242	export type AppType = typeof honoApp;
243

