import {useQuery} from "@tanstack/react-query";
import {CLP_STORAGE_ENGINES} from "@webui/common/config";
import {hc} from "hono/client";
import dayjs from "dayjs";

import type {AppType} from "@webui/server/hono-app";
import {useClppSettingsStore} from "@/features/clpp/stores/clpp-settings-store";

import {SETTINGS_STORAGE_ENGINE} from "../../../config";
import {fetchDatasetNames} from "../../SearchPage/SearchControls/Dataset/sql";
import Files from "./Files";
import styles from "./index.module.css";
import Logtypes from "./Logtypes";
import Messages from "./Messages";
import Schema from "./Schema";
import SharedNodes from "./SharedNodes";
import {
    DETAILS_DEFAULT,
    fetchClpDetails,
    fetchClpsDetails,
} from "./sql";
import TimeRange from "./TimeRange";


const api = hc<AppType>("/");


/**
 * Renders grid with compression details.
 *
 * @return
 */
const Details = () => {
    const experimentalMode = useClppSettingsStore((s) => s.experimentalMode);

    const {data: datasetNames = [], isSuccess: isSuccessDatasetNames} = useQuery({
        queryKey: ["datasets"],
        queryFn: fetchDatasetNames,
        enabled: CLP_STORAGE_ENGINES.CLP_S === SETTINGS_STORAGE_ENGINE,
    });

    const {data: details = DETAILS_DEFAULT, isPending} = useQuery({
        queryKey: [
            "details",
            datasetNames,
        ],
        queryFn: async () => {
            if (CLP_STORAGE_ENGINES.CLP === SETTINGS_STORAGE_ENGINE) {
                return fetchClpDetails();
            }

            return fetchClpsDetails(datasetNames);
        },
        enabled: CLP_STORAGE_ENGINES.CLP === SETTINGS_STORAGE_ENGINE || isSuccessDatasetNames,
    });

    const {data: clppData, isPending: isClppPending} = useQuery({
        queryKey: ["logtype-stats"],
        queryFn: async () => {
            const res = await api.api.logtype_stats.$get({
                query: {archive_id: "latest"},
            });
            return res.json();
        },
        enabled: experimentalMode,
    });

    if (CLP_STORAGE_ENGINES.CLP === SETTINGS_STORAGE_ENGINE) {
        return (
            <div className={styles["detailsGrid"]}>
                <div className={styles["timeRange"]}>
                    <TimeRange
                        beginDate={dayjs.utc(details.begin_timestamp)}
                        endDate={dayjs.utc(details.end_timestamp)}
                        isLoading={isPending}/>
                </div>
                <Messages
                    isLoading={isPending}
                    numMessages={details.num_messages}/>
                <Files
                    isLoading={isPending}
                    numFiles={details.num_files}/>
                {experimentalMode && (
                    <>
                        <Logtypes
                            isLoading={isClppPending}
                            numLogtypes={clppData?.logtypes?.length ?? null}/>
                        <Schema
                            hasSchema={Boolean(clppData?.logtypes?.length)}
                            isLoading={isClppPending}/>
                        <SharedNodes
                            isLoading={isClppPending}
                            numSharedNodes={clppData?.sharedNodeWarnings?.length ?? null}/>
                    </>
                )}
            </div>
        );
    }

    return (
        <div>
            <TimeRange
                beginDate={dayjs.utc(details.begin_timestamp)}
                endDate={dayjs.utc(details.end_timestamp)}
                isLoading={isPending}/>
            {experimentalMode && (
                <div className={styles["clppDetailsGrid"]}>
                    <Logtypes
                        isLoading={isClppPending}
                        numLogtypes={clppData?.logtypes?.length ?? null}/>
                    <Schema
                        hasSchema={Boolean(clppData?.logtypes?.length)}
                        isLoading={isClppPending}/>
                    <SharedNodes
                        isLoading={isClppPending}
                        numSharedNodes={clppData?.sharedNodeWarnings?.length ?? null}/>
                </div>
            )}
        </div>
    );
};

export default Details;

