import {useQuery} from "@tanstack/react-query";
import {CLP_STORAGE_ENGINES} from "@webui/common/config";
import dayjs from "dayjs";

import {SETTINGS_STORAGE_ENGINE} from "../../../config";
import {fetchDatasetNames} from "../../SearchPage/SearchControls/Dataset/sql";
import Files from "./Files";
import styles from "./index.module.css";
import Messages from "./Messages";
import {
    DETAILS_DEFAULT,
    fetchClpDetails,
    fetchClpsDetails,
} from "./sql";
import TimeRange from "./TimeRange";


/**
 * Renders grid with compression details.
 *
 * @return
 */
const Details = () => {
    const {data: datasetNames = [], isSuccess: isSuccessDatasetNames} = useQuery({
        queryKey: ["datasets"],
        queryFn: fetchDatasetNames,
        enabled: CLP_STORAGE_ENGINES.CLP_S === SETTINGS_STORAGE_ENGINE,
    });

    const {data: details = DETAILS_DEFAULT, isPending} = useQuery({
        queryKey: [
            "details",
            datasetNames,
        ],
        queryFn: async () => {
            if (CLP_STORAGE_ENGINES.CLP === SETTINGS_STORAGE_ENGINE) {
                return fetchClpDetails();
            }

            return fetchClpsDetails(datasetNames);
        },
        enabled: CLP_STORAGE_ENGINES.CLP === SETTINGS_STORAGE_ENGINE || isSuccessDatasetNames,
    });

    if (CLP_STORAGE_ENGINES.CLP === SETTINGS_STORAGE_ENGINE) {
        return (
            <div className={styles["detailsGrid"]}>
                <div className={styles["timeRange"]}>
                    <TimeRange
                        beginDate={dayjs.utc(details.begin_timestamp)}
                        endDate={dayjs.utc(details.end_timestamp)}
                        isLoading={isPending}/>
                </div>
                <Messages
                    isLoading={isPending}
                    numMessages={details.num_messages}/>
                <Files
                    isLoading={isPending}
                    numFiles={details.num_files}/>
            </div>
        );
    }

    return (
        <div>
            <TimeRange
                beginDate={dayjs.utc(details.begin_timestamp)}
                endDate={dayjs.utc(details.end_timestamp)}
                isLoading={isPending}/>
        </div>
    );
};

export default Details;

import {
    Card,
    Typography,
} from "antd";

import styles from "./index.module.css";


const {Text} = Typography;

interface DashboardCardProps {
    title: string;
    titleColor?: string;
    backgroundColor?: string;
    children?: React.ReactNode;
    isLoading?: boolean;
    titleExtra?: React.ReactNode;
}

/**
 * Renders a card for dashboard.
 *
 * @param props
 * @param props.title
 * @param props.titleColor
 * @param props.backgroundColor
 * @param props.children
 * @param props.isLoading
 * @return
 */
const DashboardCard = ({
    title,
    titleColor,
    backgroundColor,
    children,
    isLoading = false,
    titleExtra,
}: DashboardCardProps) => {
    return (
        <Card
            className={styles["card"] || ""}
            hoverable={true}
            loading={isLoading}
            style={{backgroundColor}}
        >
            <div className={styles["cardContent"]}>
                <div className={styles["titleRow"]}>
                    <Text
                        className={styles["title"] || ""}
                        style={{color: titleColor}}
                    >
                        {title}
                    </Text>
                    {titleExtra}
                </div>
                {children}
            </div>
        </Card>
    );
};

export {DashboardCard};

export type {DashboardCardProps};

.detailsGrid {
    display: grid;
    grid-template-columns: repeat(2, minmax(200px, 1fr));
    gap: 8px;
}

.detailsGridClpp {
    display: grid;
    grid-template-columns: repeat(3, minmax(200px, 1fr));
    gap: 8px;
}

.timeRange {
    display: flex;
    grid-column: span 2;
}

.timeRangeThreeCol {
    display: flex;
    grid-column: span 3;
}

.timeRange :global(.ant-card),
.timeRangeThreeCol :global(.ant-card) {
    flex: 1;
}

.clppDetailsGrid {
    display: grid;
    grid-template-columns: repeat(3, minmax(200px, 1fr));
    gap: 8px;
    margin-top: 8px;
}

.card :global(.ant-card-head) {
    border: 0px;
}

.cardContent {
    display: flex;
    flex-direction: column;
}

.titleRow {
    display: flex;
    align-items: center;
    gap: 8px;
}

.title {
    font-size: 1.5rem;
    font-weight: 600;
}

import {Tag} from "antd";
import {Nullable} from "@webui/common/utility-types";

import {DashboardCard} from "../../../components/DashboardCard";
import Stat from "../../../components/Stat";


interface SharedNodesProps {
    numSharedNodes: Nullable<number>;
    isLoading: boolean;
}

const CLPP_TAG = <Tag color={"purple"}>CLPP</Tag>;

/**
 * Renders the shared nodes statistic with a [CLPP] badge.
 * Shows a warning tag when shared nodes are detected.
 *
 * @param props
 * @param props.numSharedNodes
 * @param props.isLoading
 * @return
 */
const SharedNodes = ({numSharedNodes, isLoading}: SharedNodesProps) => {
    const count = numSharedNodes ?? 0;

    return (
        <DashboardCard
            isLoading={isLoading}
            title={"Shared Nodes"}
            titleExtra={CLPP_TAG}
        >
            <Stat text={count.toString()}/>
            {0 < count && (
                <Tag color={"warning"} style={{marginTop: 4}}>
                    Warning
                </Tag>
            )}
        </DashboardCard>
    );
};

export default SharedNodes;

