import type {Nullable} from "@webui/common/utility-types";
import {Tag} from "antd";
import type {FC} from "react";

import {DashboardCard} from "../../../components/DashboardCard";
import Stat from "../../../components/Stat";


interface LogtypesProps {
    numLogtypes: Nullable<number>;
    isLoading: boolean;
}

const CLPP_TAG = <Tag color={"purple"}>CLPP</Tag>;

/**
 * Renders the logtypes statistic with a [CLPP] badge.
 *
 * @param props
 * @param props.numLogtypes
 * @param props.isLoading
 * @return
 */
const Logtypes: FC<LogtypesProps> = ({numLogtypes, isLoading}) => {
    return (
        <DashboardCard
            isLoading={isLoading}
            title={"Logtypes"}
            titleExtra={CLPP_TAG}
        >
            <Stat text={(numLogtypes ?? 0).toString()}/>
        </DashboardCard>
    );
};

export default Logtypes;

import {Tag} from "antd";
import type {FC} from "react";

import {DashboardCard} from "../../../components/DashboardCard";
import Stat from "../../../components/Stat";


interface SchemaProps {
    hasSchema: boolean;
    isLoading: boolean;
}

const CLPP_TAG = <Tag color={"purple"}>CLPP</Tag>;

/**
 * Renders the schema indicator with a [CLPP] badge.
 *
 * @param props
 * @param props.hasSchema
 * @param props.isLoading
 * @return
 */
const Schema: FC<SchemaProps> = ({hasSchema, isLoading}) => {
    return (
        <DashboardCard
            isLoading={isLoading}
            title={"Schema"}
            titleExtra={CLPP_TAG}
        >
            <Stat
                text={hasSchema ?
                    "Yes" :
                    "No"}/>
        </DashboardCard>
    );
};

export default Schema;

import type {Nullable} from "@webui/common/utility-types";
import {Tag} from "antd";
import type {FC} from "react";

import {DashboardCard} from "../../../components/DashboardCard";
import Stat from "../../../components/Stat";


interface SharedNodesProps {
    numSharedNodes: Nullable<number>;
    isLoading: boolean;
}

const CLPP_TAG = <Tag color={"purple"}>CLPP</Tag>;

/**
 * Renders the shared nodes statistic with a [CLPP] badge.
 * Shows a warning tag when shared nodes are detected.
 *
 * @param props
 * @param props.numSharedNodes
 * @param props.isLoading
 * @return
 */
const SharedNodes: FC<SharedNodesProps> = ({numSharedNodes, isLoading}) => {
    const count = numSharedNodes ?? 0;

    return (
        <DashboardCard
            isLoading={isLoading}
            title={"Shared Nodes"}
            titleExtra={CLPP_TAG}
        >
            <Stat text={count.toString()}/>
            {0 < count && (
                <Tag
                    color={"warning"}
                    style={{marginTop: 4}}
                >
                    Warning
                </Tag>
            )}
        </DashboardCard>
    );
};

export default SharedNodes;

import {useQuery} from "@tanstack/react-query";
import {CLP_STORAGE_ENGINES} from "@webui/common/config";
import type {AppType} from "@webui/server/hono-app";
import dayjs from "dayjs";
import {hc} from "hono/client";

import {useClppSettingsStore} from "@/features/clpp/stores/clpp-settings-store";

import {SETTINGS_STORAGE_ENGINE} from "../../../config";
import {fetchDatasetNames} from "../../ExplorePage/SearchControls/Dataset/sql";
import Files from "./Files";
import styles from "./index.module.css";
import Logtypes from "./Logtypes";
import Messages from "./Messages";
import Schema from "./Schema";
import SharedNodes from "./SharedNodes";
import {
    DETAILS_DEFAULT,
    fetchClpDetails,
    fetchClpsDetails,
} from "./sql";
import TimeRange from "./TimeRange";


const api = hc<AppType>("/");


/**
 * Renders the three CLPP-specific detail cards (Logtypes, Schema, Shared Nodes).
 *
 * @param props
 * @param props.clppData
 * @param props.isClppPending
 * @return
 */
const ClppDetailsCards = ({
    clppData,
    isClppPending,
}: {
    clppData: {
        logtypes: {length: number};
        sharedNodeWarnings: {length: number};
    } | undefined;
    isClppPending: boolean;
}) => {
    const numLogtypes = clppData?.logtypes.length ?? null;
    const numSharedNodes = clppData?.sharedNodeWarnings.length ?? null;
    const hasSchema = null !== numLogtypes && 0 < numLogtypes;

    return (
        <>
            <Logtypes
                isLoading={isClppPending}
                numLogtypes={numLogtypes}/>
            <Schema
                hasSchema={hasSchema}
                isLoading={isClppPending}/>
            <SharedNodes
                isLoading={isClppPending}
                numSharedNodes={numSharedNodes}/>
        </>
    );
};


/**
 * Renders CLP storage engine details grid (TimeRange + Messages + Files +
 * optional CLPP cards).
 *
 * @param props
 * @param props.details
 * @param props.isPending
 * @param props.experimentalMode
 * @param props.clppData
 * @param props.isClppPending
 * @return
 */
const ClpDetails = ({
    details,
    isPending,
    experimentalMode,
    clppData,
    isClppPending,
}: {
    details: typeof DETAILS_DEFAULT;
    isPending: boolean;
    experimentalMode: boolean;
    clppData: {
        logtypes: {length: number};
        sharedNodeWarnings: {length: number};
    } | undefined;
    isClppPending: boolean;
}) => {
    return (
        <div
            className={experimentalMode ?
                styles["detailsGridClpp"] :
                styles["detailsGrid"]}
        >
            <div
                className={experimentalMode ?
                    styles["timeRangeThreeCol"] :
                    styles["timeRange"]}
            >
                <TimeRange
                    beginDate={dayjs.utc(details.begin_timestamp)}
                    endDate={dayjs.utc(details.end_timestamp)}
                    isLoading={isPending}/>
            </div>
            <Messages
                isLoading={isPending}
                numMessages={details.num_messages}/>
            <Files
                isLoading={isPending}
                numFiles={details.num_files}/>
            {experimentalMode && (
                <ClppDetailsCards
                    clppData={clppData}
                    isClppPending={isClppPending}/>
            )}
        </div>
    );
};


/**
 * Renders CLP-S storage engine details (TimeRange + optional CLPP grid).
 *
 * @param props
 * @param props.details
 * @param props.isPending
 * @param props.experimentalMode
 * @param props.clppData
 * @param props.isClppPending
 * @return
 */
const ClpsDetails = ({
    details,
    isPending,
    experimentalMode,
    clppData,
    isClppPending,
}: {
    details: typeof DETAILS_DEFAULT;
    isPending: boolean;
    experimentalMode: boolean;
    clppData: {
        logtypes: {length: number};
        sharedNodeWarnings: {length: number};
    } | undefined;
    isClppPending: boolean;
}) => {
    return (
        <div>
            <TimeRange
                beginDate={dayjs.utc(details.begin_timestamp)}
                endDate={dayjs.utc(details.end_timestamp)}
                isLoading={isPending}/>
            {experimentalMode && (
                <div className={styles["clppDetailsGrid"]}>
                    <ClppDetailsCards
                        clppData={clppData}
                        isClppPending={isClppPending}/>
                </div>
            )}
        </div>
    );
};


/**
 * Renders grid with compression details.
 *
 * @return
 */
const Details = () => {
    const experimentalMode = useClppSettingsStore((s) => s.experimentalMode);

    const {data: datasetNames = [], isSuccess: isSuccessDatasetNames} = useQuery({
        queryKey: ["datasets"],
        queryFn: fetchDatasetNames,
        enabled: CLP_STORAGE_ENGINES.CLP_S === SETTINGS_STORAGE_ENGINE,
    });

    const {data: details = DETAILS_DEFAULT, isPending} = useQuery({
        queryKey: [
            "details",
            datasetNames,
        ],
        queryFn: async () => {
            if (CLP_STORAGE_ENGINES.CLP === SETTINGS_STORAGE_ENGINE) {
                return fetchClpDetails();
            }

            return fetchClpsDetails(datasetNames);
        },
        enabled: CLP_STORAGE_ENGINES.CLP === SETTINGS_STORAGE_ENGINE || isSuccessDatasetNames,
    });

    const {data: clppData, isPending: isClppPending} = useQuery({
        queryKey: ["logtype-stats"],
        queryFn: async () => {
            const res = await api.api["logtype-stats"].$get({
                query: {archive_id: "latest"},
            });

            return res.json();
        },
        enabled: experimentalMode,
    });

    if (CLP_STORAGE_ENGINES.CLP === SETTINGS_STORAGE_ENGINE) {
        return (
            <ClpDetails
                clppData={clppData}
                details={details}
                experimentalMode={experimentalMode}
                isClppPending={isClppPending}
                isPending={isPending}/>
        );
    }

    return (
        <ClpsDetails
            clppData={clppData}
            details={details}
            experimentalMode={experimentalMode}
            isClppPending={isClppPending}
            isPending={isPending}/>
    );
};

export default Details;

